try { $pdo->query("UPDATE library_borrows SET status='Overdue' WHERE status='Borrowed' AND due_date < CURDATE()"); } catch(Exception $e){}
$sd=['total_titles'=>0,'total_copies'=>0,'available'=>0,'borrowed'=>0,'overdue'=>0,'total_returned'=>0,'returned_today'=>0,'lost'=>0,'fines_due'=>0,'fines_paid'=>0,'pending_requests'=>0,'return_requests'=>0,'total_students'=>0,'total_teachers'=>0,'students_with_books'=>0,'teachers_with_books'=>0];
try{$stats=$pdo->query("SELECT (SELECT COUNT(*) FROM library_books WHERE is_active=1) AS total_titles,(SELECT COALESCE(SUM(total_copies),0) FROM library_books WHERE is_active=1) AS total_copies,(SELECT COALESCE(SUM(available_copies),0) FROM library_books WHERE is_active=1) AS available,(SELECT COUNT(*) FROM library_borrows WHERE status IN('Borrowed','Overdue')) AS borrowed,(SELECT COUNT(*) FROM library_borrows WHERE status='Overdue') AS overdue,(SELECT COUNT(*) FROM library_borrows WHERE status='Returned') AS total_returned,(SELECT COUNT(*) FROM library_borrows WHERE status='Returned' AND DATE(returned_at)=CURDATE()) AS returned_today,(SELECT COUNT(*) FROM library_borrows WHERE status='Lost') AS lost,(SELECT COALESCE(SUM(fine_amount),0) FROM library_borrows WHERE fine_amount>0) AS fines_due,(SELECT COALESCE(SUM(fine_amount),0) FROM library_borrows WHERE fine_amount>0 AND status='Returned') AS fines_paid,(SELECT COUNT(*) FROM library_requests WHERE status='Pending') AS pending_requests,(SELECT COUNT(*) FROM library_borrows WHERE status='Return Requested') AS return_requests,(SELECT COUNT(*) FROM students WHERE status='Active') AS total_students,(SELECT COUNT(*) FROM teachers WHERE status='Active') AS total_teachers,(SELECT COUNT(DISTINCT student_id) FROM library_borrows WHERE borrower_type='student' AND status IN('Borrowed','Overdue')) AS students_with_books,(SELECT COUNT(DISTINCT teacher_id) FROM library_borrows WHERE borrower_type='teacher' AND status IN('Borrowed','Overdue')) AS teachers_with_books")->fetch()?:$sd;}catch(Exception $e){$stats=$sd;}
try{$top_books=$pdo->query("SELECT bk.title,bk.author,COUNT(lb.id) AS cnt FROM library_borrows lb JOIN library_books bk ON lb.book_id=bk.id GROUP BY lb.book_id ORDER BY cnt DESC LIMIT 8")->fetchAll();}catch(Exception $e){$top_books=[];}
try{$recent=$pdo->query("SELECT lb.*,bk.title,COALESCE(CONCAT(s.first_name,' ',s.last_name),CONCAT(t.first_name,' ',t.last_name)) AS borrower_name,lb.borrower_type FROM library_borrows lb JOIN library_books bk ON lb.book_id=bk.id LEFT JOIN students s ON lb.student_id=s.id LEFT JOIN teachers t ON lb.teacher_id=t.id ORDER BY lb.borrowed_at DESC LIMIT 8")->fetchAll();}catch(Exception $e){$recent=[];}
try{$new_books=$pdo->query("SELECT * FROM library_books WHERE is_active=1 ORDER BY id DESC LIMIT 6")->fetchAll();}catch(Exception $e){$new_books=[];}
require_once '../../includes/header.php';
try{$trend=$pdo->query("SELECT DATE_FORMAT(borrowed_at,'%b %Y') AS mo,COUNT(*) AS cnt FROM library_borrows WHERE borrowed_at>=DATE_SUB(NOW(),INTERVAL 6 MONTH) GROUP BY DATE_FORMAT(borrowed_at,'%Y-%m') ORDER BY DATE_FORMAT(borrowed_at,'%Y-%m')")->fetchAll();}catch(Exception $e){$trend=[];}
try{$cats=$pdo->query("SELECT COALESCE(category,'Uncategorized') AS cat,COUNT(*) AS cnt FROM library_books WHERE is_active=1 GROUP BY category ORDER BY cnt DESC LIMIT 8")->fetchAll();}catch(Exception $e){$cats=[];}
$fd='$'.number_format($stats['fines_due'],2);
$fp='$'.number_format($stats['fines_paid'],2);
