  <div style="background:#fff;border-radius:14px;box-shadow:0 2px 10px rgba(0,0,0,.06);overflow:hidden"><div style="padding:18px 22px;border-bottom:1px solid #f1f5f9"><div style="font-weight:800;font-size:.92rem;color:#1e293b"><i class="fas fa-fire" style="color:#f59e0b;margin-right:7px"></i>Most Borrowed</div></div><?php if($top_books):$pal=['#4361ee','#7209b7','#10b981','#f59e0b','#e63946','#0891b2','#8b5cf6','#06b6d4'];$mx=$top_books[0]['cnt'];foreach($top_books as $i=>$b):$c=$pal[$i%8];$pct=$mx>0?round($b['cnt']/$mx*100):0;?><div style="padding:12px 22px;border-bottom:1px solid #f8fafc;display:flex;align-items:center;gap:12px"><div style="width:30px;height:30px;border-radius:9px;background:<?=$c?>;color:#fff;display:flex;align-items:center;justify-content:center;font-size:.78rem;font-weight:800;flex-shrink:0"><?=$i+1?></div><div style="flex:1;min-width:0"><div style="font-weight:700;font-size:.83rem;color:#1e293b;white-space:nowrap;overflow:hidden;text-overflow:ellipsis"><?=e($b['title'])?></div><div style="margin-top:4px;height:4px;background:#f1f5f9;border-radius:2px"><div style="height:100%;width:<?=$pct?>%;background:<?=$c?>;border-radius:2px"></div></div></div><div style="text-align:right;flex-shrink:0"><div style="font-size:.9rem;font-weight:800;color:#1e293b"><?=$b['cnt']?></div><div style="font-size:.62rem;color:#94a3b8">borrows</div></div></div><?php endforeach;else:?><div style="padding:44px;text-align:center;color:#cbd5e1"><i class="fas fa-book" style="font-size:2rem;display:block;margin-bottom:10px;opacity:.35"></i><div style="font-size:.85rem">No borrow records yet</div></div><?php endif;?></div>
  <div style="background:#fff;border-radius:14px;box-shadow:0 2px 10px rgba(0,0,0,.06);overflow:hidden"><div style="padding:18px 22px;border-bottom:1px solid #f1f5f9;display:flex;justify-content:space-between;align-items:center"><div style="font-weight:800;font-size:.92rem;color:#1e293b"><i class="fas fa-history" style="color:#10b981;margin-right:7px"></i>Recent Activity</div><a href="librarian_desk.php?tab=active" style="font-size:.76rem;color:#4361ee;text-decoration:none;font-weight:700">View all</a></div><?php if($recent):foreach($recent as $a):$st=$a['status'];if($st==='Borrowed'){$sc=['#fef9c3','#92400e','#f59e0b','fas fa-hand-holding-heart'];}elseif($st==='Returned'){$sc=['#dcfce7','#166534','#10b981','fas fa-undo'];}elseif($st==='Overdue'){$sc=['#fee2e2','#991b1b','#e63946','fas fa-exclamation-triangle'];}elseif($st==='Lost'){$sc=['#fce7f3','#9d174d','#ec4899','fas fa-times-circle'];}else{$sc=['#f1f5f9','#475569','#94a3b8','fas fa-circle'];}?><div style="padding:12px 22px;border-bottom:1px solid #f8fafc;display:flex;align-items:center;gap:12px"><div style="width:38px;height:38px;border-radius:11px;background:<?=$sc[0]?>;display:flex;align-items:center;justify-content:center;flex-shrink:0"><i class="<?=$sc[3]?>" style="color:<?=$sc[2]?>;font-size:.88rem"></i></div><div style="flex:1;min-width:0"><div style="font-weight:700;font-size:.83rem;color:#1e293b;white-space:nowrap;overflow:hidden;text-overflow:ellipsis"><?=e($a['title'])?></div><div style="font-size:.73rem;color:#94a3b8;margin-top:1px"><?=e($a['borrower_name']??'—')?> &middot; <?=$a['borrower_type']?></div></div><div style="text-align:right;flex-shrink:0"><span style="background:<?=$sc[0]?>;color:<?=$sc[1]?>;border-radius:7px;padding:2px 8px;font-size:.68rem;font-weight:700"><?=$st?></span><div style="font-size:.65rem;color:#cbd5e1;margin-top:2px"><?=date('M j',strtotime($a['borrowed_at']))?></div></div></div><?php endforeach;else:?><div style="padding:44px;text-align:center;color:#cbd5e1"><i class="fas fa-history" style="font-size:2rem;display:block;margin-bottom:10px;opacity:.35"></i><div style="font-size:.85rem">No activity yet</div></div><?php endif;?></div>
</div>
<?php if($new_books):?><div style="margin-bottom:24px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px"><div style="font-weight:800;font-size:.95rem;color:#1e293b"><i class="fas fa-plus-circle" style="color:#10b981;margin-right:8px"></i>Recently Added Books</div><a href="index.php" style="font-size:.78rem;color:#4361ee;text-decoration:none;font-weight:700">View all catalog</a></div><div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:14px"><?php foreach($new_books as $bk):$colors=['#4361ee','#7209b7','#10b981','#f59e0b','#e63946','#0891b2'];$c=$colors[abs(crc32($bk['title']))%count($colors)];?><div style="background:#fff;border-radius:12px;box-shadow:0 2px 8px rgba(0,0,0,.06);overflow:hidden"><div style="height:6px;background:<?=$c?>"></div><div style="padding:14px"><div style="font-weight:700;font-size:.85rem;color:#1e293b;margin-bottom:4px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis"><?=e($bk['title'])?></div><div style="font-size:.75rem;color:#64748b;margin-bottom:8px"><?=e($bk['author'])?></div><div style="display:flex;justify-content:space-between;align-items:center"><span style="font-size:.7rem;background:<?=$c?>18;color:<?=$c?>;padding:2px 8px;border-radius:6px;font-weight:600"><?=e($bk['category']??'General')?></span><span style="font-size:.75rem;font-weight:700;color:<?=$bk['available_copies']>0?'#10b981':'#e63946'?>"><?=$bk['available_copies']?>/<?=$bk['total_copies']?> avail</span></div></div></div><?php endforeach;?></div></div><?php endif;?>
<?php if($trend||$cats):?><script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.0/dist/chart.umd.min.js"></script><script>const p=['#4361ee','#7209b7','#10b981','#f59e0b','#e63946','#0891b2','#8b5cf6','#06b6d4'];<?php if($trend):?>new Chart(document.getElementById('bc'),{type:'bar',data:{labels:<?=json_encode(array_column($trend,'mo'))?>,datasets:[{label:'Borrows',data:<?=json_encode(array_column($trend,'cnt'))?>,backgroundColor:p[0]+'cc',borderRadius:7,borderSkipped:false}]},options:{maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{y:{beginAtZero:true,ticks:{stepSize:1,font:{size:10}},grid:{color:'#f1f5f9'},border:{display:false}},x:{ticks:{font:{size:10}},grid:{display:false},border:{display:false}}}}});<?php endif;?><?php if($cats):?>new Chart(document.getElementById('cc'),{type:'doughnut',data:{labels:<?=json_encode(array_column($cats,'cat'))?>,datasets:[{data:<?=json_encode(array_column($cats,'cnt'))?>,backgroundColor:p,borderWidth:3,borderColor:'#fff',hoverOffset:5}]},options:{maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{font:{size:9},boxWidth:9,padding:6}}},cutout:'58%'}});<?php endif;?></script><?php endif;?>
